{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the Rydberg energy for a specific exciton state using the relationship between the 1s binding energy and the Rydberg constant. I will split this into finding the effective Rydberg constant and then calculating the energy for n=3.",
  "helpers": [
    {
      "label": "calculate_rydberg_constant",
      "instructions": "Given a 1s exciton binding energy of 1 eV, calculate the effective Rydberg energy (Ry*) for this system. Note that for the 1s state, the binding energy is equal to Ry*. Provide the value of Ry* in eV."
    },
    {
      "label": "calculate_n3_energy",
      "instructions": "Given the effective Rydberg energy (Ry*) calculated by the previous helper, calculate the binding energy for the n = 3 exciton state using the formula E_n = Ry* / n^2. Provide the final numerical value. Ensure you consider if the question asks for the binding energy or the total energy relative to the band edge, but specifically focus on the energy value associated with the n=3 state."
    }
  ],
  "synthesis_brief": "The parent will take the effective Rydberg constant (Ry*) from the first helper and use it to compute the n=3 binding energy. The final answer should be the binding energy for n=3, expressed as a numerical value. The sign should be treated as a binding energy (positive value relative to the band edge or negative relative to the vacuum/conduction band depending on convention, but typically Rydberg energy refers to the magnitude or the binding energy value)."
}

